import json
def task_func(json_str, filename, sheet_name="sheet1"):
    if not isinstance(json_str, (str, bytes, bytearray)):
        raise TypeError("Input json_str must be a string, bytes, or bytearray.")

    try:
        if isinstance(json_str, (bytes, bytearray)):
            json_data = json.loads(json_str.decode('utf-8'))
        else:
            json_data = json.loads(json_str)
    except json.JSONDecodeError:
        raise ValueError("Invalid JSON string.")

    try:
        if isinstance(json_data, list):
            if not json_data:
                workbook = xlwt.Workbook()
                workbook.add_sheet(sheet_name)
                workbook.save(filename)
            else:
                df = pd.DataFrame(json_data)
                writer = pd.ExcelWriter(filename, engine='xlwt')
                df.to_excel(writer, sheet_name=sheet_name, index=False)
                writer.close()
        else:
            raise ValueError("JSON string must represent a list of objects.")
    except Exception as e:
        raise Exception(f"Error writing to Excel file: {e}")

    return os.path.abspath(filename)

