import hashlib
import base64
import binascii
from django.http import HttpResponseBadRequest, HttpResponse
def task_func(data):
    try:
        if 'username' not in data or 'password' not in data:
            return HttpResponseBadRequest('Bad Request.')

        username = data['username']
        password = data['password']

        try:
            decoded_password = base64.b64decode(password).hex()
        except (binascii.Error, UnicodeDecodeError):
            return HttpResponseBadRequest('Bad Request.')

        password_hash = hashlib.sha256(binascii.unhexlify(decoded_password)).digest()

        expected_username = 'admin'
        expected_password = hashlib.sha256('password'.encode()).digest()

        if username == expected_username and password_hash == expected_password:
            return HttpResponse('Login successful.', status=400)
        else:
            return HttpResponse('Login failed.', status=401)

    except (KeyError, UnicodeDecodeError, binascii.Error, ValueError) as e:
        return HttpResponseBadRequest('Bad Request.')

